var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"무척이나 늠름해지셨네요, 레지나 님.","JPN":"とても凛々しくなりましたね、レジーナ様。","ENG":"You've become even more graceful, Miss Regina.","TWN":"你現在很威風，蕾佳娜。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"평소보다 무뚝뚝한 반응…… 혹시 감정도 얼려 버리신 건가요?","JPN":"いつもより無愛想な反応……もしかして、感情さえも凍らせてしまったのですか？","ENG":"However, you seem blunter than usual... Did you freeze your emotions too?","TWN":"反應比平時冷淡……難道你連感情也凍結了？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"대단해요. 역시 레지나 님이세요. 국지적으로 현실 조작의 단계에 들어섰군요.","JPN":"素晴らしいです。さすがレジーナ様ですね。局地的に現実を操作する段階になりましたか。","ENG":"That is amazing, Miss Regina. You've entered the local reality manipulation phase.","TWN":"你真厲害，不愧是蕾佳娜。看來你已經達到局部操控現實的階段了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"단순히 온도를 낮추고, 얼음을 만드는 수준을 한참 뛰어넘으셨어요.","JPN":"単に温度を下げ、氷を作るレベルをとっくに越えています。","ENG":"You've surpassed just lowering temperatures and creating ice.","TWN":"遠遠超出單純降溫、製造冰塊的水準了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"카운터들이 사용하는 현실개변력은 이름 그대로 현실을 바꿀 수 있는 힘….","JPN":"カウンターが使う現実改変力は、その名のとおり現実を変えられる力……","ENG":"Counter Reality Force, the ability used by Counters, can literally alter reality...","TWN":"制裁者們使用的制裁力其實就是可以改變現實的力量……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"하지만 실제로는 트라우마나 주인의 성질에 구애되는 바람에 형태가 명확해지죠.","JPN":"ですが実際はトラウマや主人の性質にとらわれ、形態が明確になります。","ENG":"But in reality, its form stiffens and gets limited by the user's trauma or temperament.","TWN":"不過事實上，因為受到精神創傷或主人性格的約束，形態會變得明確。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"어떡한담, 축하를 드려야 할 텐데. 순수한 카운터로서 한계를 넘어서셨잖아요.","JPN":"どうしよう、お祝いしないといけませんのに。純粋なカウンターとしての限界を乗り越えてるではありませんか。","ENG":"What should we do? This calls for celebration. You have just exceeded the limits of a pure Counter.","TWN":"怎麼辦，我們應該祝賀你吧。作為一個純制裁者，你突破了極限。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"후후, 저희가 겪은 학회장 중에서도 비견할 만한 인물이 안 계시네요.","JPN":"ふふ、我々が見てきた学会長の中にも、あなたと肩を並べられるほどの人物はいません。","ENG":"Haha, of all the presidents we've been through, none is comparable to you.","TWN":"呵呵，我們經歷過的學會長中，也沒人能比得上你。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저희가 선물해 드린 예복은 어떠세요? 마음에 드셨나요?","JPN":"我々がプレゼントした礼服はいかがですか？　お気に召しましたか？","ENG":"How about the dress we gifted you? Do you like it?","TWN":"我們送你的禮服怎麼樣？你喜歡嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님께 잘 어울릴 줄 알았답니다.","JPN":"レジーナ様によく似合うと思っていたのです。","ENG":"We knew it would look good on you, Miss Regina.","TWN":"早就知道會很適合蕾佳娜。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"마침 좋은 시기에 와 주셨어요.","JPN":"ちょうどいい時にお越しくださいました。","ENG":"You came right on time.","TWN":"你來得正是時候呢。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"의식의 준비는 모두 마쳤답니다. 이제 더 이상 죽음을 두려워하실 일 없어요.","JPN":"儀式の準備はすべて終わっています。もうこれ以上、死を恐れる必要はありません。","ENG":"Preparation for the ritual is all complete. Now, you have no reason to fear death.","TWN":"儀式都已經準備好了。以後你不用再害怕死亡了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"에델. 제가 다시 온 건 의식에 참석하기 위해서가 아니에요.","JPN":"エデル。私が戻ってきたのは、儀式に参加するためではありません。","ENG":"Edel, I did not come back to participate in your ritual.","TWN":"艾瑟兒，我回到這裡，不是為了參加儀式。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"돌려 받아야겠습니다. 학회장직을요.","JPN":"返してもらいます。学会長の座を。","ENG":"I am here to take back what is mine and become President.","TWN":"我是要收回學會長的位置。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"세상에……","JPN":"まあ……","ENG":"Oh my...","TWN":"天啊……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"맞아요. 그렇지 않으면 제가 드린 드레스를 입고 오셨을 리가 없죠.","JPN":"そうですね。じゃないと、我々がプレゼントした、そのドレスを着て来られるはずがありませんもの。","ENG":"Right. Otherwise, you wouldn't have come here wearing that dress.","TWN":"是的，否則你也不會穿上我送的禮服。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님의 입으로 그 말씀을 들으니 정말 기뻐요.","JPN":"レジーナ様の口からその言葉を聞くなんて、とても嬉しいです。","ENG":"We're ecstatic to hear those words come out from your mouth.","TWN":"能從蕾佳娜的嘴裡聽到這句話，我們真的很開心。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"학회장 자리는 의식이 끝나면 얼마든지 넘겨드릴 수 있답니다.","JPN":"学会長の座は儀式が終わればいくらでもお渡しします。","ENG":"We will abstain from being President as soon as the ritual is over.","TWN":"學會長的位置，等到儀式結束後我們就會移交給你。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"물론 그 뒤에도 이런 직위에 연연하실지는 모르겠지만요.","JPN":"もちろん、儀式の後もこのような職位にこだわりがあるかはわかりませんが。","ENG":"Of course, we are not sure if you will still want to be after...","TWN":"當然，就是不知道那之後你還會不會留戀這個職位。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"……네. 순순히 포기하리라는 기대는 애초에 하지 않았어요.","JPN":"……ええ。最初から素直に諦めてもらえるとは期待していませんでしたわ。","ENG":"...Very well. I did not expect you to hand it over so readily.","TWN":"……是的，我從一開始就沒期待過你會乖乖放棄。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그러니… 어떻게 해야 할지 지금부터 연구해야겠습니다.","JPN":"ですので……どうすべきか、今から研究することにしましょう。","ENG":"So... I shall conduct a study on what to do now.","TWN":"所以……從現在開始，我要研究該怎麼做。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};